{
  "sentences": [
    {
      "text": "請你走進來。",
      "pinyin": "Qǐng nǐ zǒu jìnlái.",
      "pinyin_numeric": "qing3 ni3 zou3 jin4lai2",
      "translation_en": "Please walk in.",
      "translation_ko": "안으로 걸어 들어오세요."
    },
    {
      "text": "他跑出去了。",
      "pinyin": "Tā pǎo chūqù le.",
      "pinyin_numeric": "ta1 pao3 chu1qu4 le5",
      "translation_en": "He ran out.",
      "translation_ko": "그가 뛰어 나갔어요."
    },
    {
      "text": "我們一起爬上去。",
      "pinyin": "Wǒmen yīqǐ pá shàngqù.",
      "pinyin_numeric": "wo3men yi1qi3 pa2 shang4qu4",
      "translation_en": "Let's climb up together.",
      "translation_ko": "우리 함께 올라가요."
    },
    {
      "text": "貓跳下來了。",
      "pinyin": "Māo tiào xiàlái le.",
      "pinyin_numeric": "mao1 tiao4 xia4lai2 le5",
      "translation_en": "The cat jumped down.",
      "translation_ko": "고양이가 뛰어내렸어요."
    },
    {
      "text": "請把書拿出來。",
      "pinyin": "Qǐng bǎ shū ná chūlái.",
      "pinyin_numeric": "qing3 ba3 shu1 na2 chu1lai2",
      "translation_en": "Please take the book out.",
      "translation_ko": "책을 꺼내 주세요."
    },
    {
      "text": "他把手機放進去了。",
      "pinyin": "Tā bǎ shǒujī fàng jìnqù le.",
      "pinyin_numeric": "ta1 ba3 shou3ji1 fang4 jin4qu4 le5",
      "translation_en": "He put the phone in.",
      "translation_ko": "그가 핸드폰을 안에 넣었어요."
    },
    {
      "text": "妹妹走下來了。",
      "pinyin": "Mèimei zǒu xiàlái le.",
      "pinyin_numeric": "mei4mei5 zou3 xia4lai2 le5",
      "translation_en": "Little sister walked down.",
      "translation_ko": "여동생이 걸어 내려왔어요."
    },
    {
      "text": "請你帶咖啡上來。",
      "pinyin": "Qǐng nǐ dài kāfēi shànglái.",
      "pinyin_numeric": "qing3 ni3 dai4 ka1fei1 shang4lai2",
      "translation_en": "Please bring the coffee up.",
      "translation_ko": "커피를 가지고 올라와 주세요."
    },
    {
      "text": "他騎腳踏車進去了。",
      "pinyin": "Tā qí jiǎotàchē jìnqù le.",
      "pinyin_numeric": "ta1 qi2 jiao3ta4che1 jin4qu4 le5",
      "translation_en": "He rode the bicycle in.",
      "translation_ko": "그가 자전거를 타고 들어갔어요."
    },
    {
      "text": "請把垃圾拿出去。",
      "pinyin": "Qǐng bǎ lèsè ná chūqù.",
      "pinyin_numeric": "qing3 ba3 le4se4 na2 chu1qu4",
      "translation_en": "Please take the trash out.",
      "translation_ko": "쓰레기를 밖으로 가져가 주세요."
    }
  ]
}
